<template>
    <form class="settings-form" v-on:submit.prevent="onSubmit">
        <h1 class="main-title">
            <p>отстройка</p>
            <span>{{collectionName}}</span>
        </h1>
        <manufactureOrderList :basket="basket"></manufactureOrderList>
        <input id="send-form" type="submit" v-if="activeForm && !message" value="сохранить">
        <div v-if="message">{{message}}</div>
    </form>
</template>
<script>
import settings from '../../settings'
import ManufactureOrderList from "@/components/manufacture/list";
export default {
    name: 'manufactureForm',
    components: {
        ManufactureOrderList
    },
    data: function(){
        return {
            activeForm: true,
            id: 0,
            collectionName: "",
            orderId: 0,
            basket: [],
            quantity: [],
            message: ""
        }
    },
    methods: {
        onSubmit(){
            let self = this;
            this.message = "Обработка запроса...";

            let requestData = {
                "id": this.id,
                "title": this.collectionName,
                "orderId": this.orderId,
                "basket": this.quantity || []
            };

            this.$axios({
                method: 'POST',
                url: settings.apiUrl + '/manufacture/0/create/',
                data: requestData
            }).then(resp => {
                let result = resp.data.data;

                self.message = "Сохранено!";
                
                self.$bvToast.toast('Отстройка успешно сформирована!', {
                    title: 'Создание отстройки по презентации',
                    autoHideDelay: 2000,
                    variant: 'success',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });

                setTimeout(function(){
                    self.$router.push('/manufacture-list');
                }, 2000);
            })
            .catch(err => {
                console.log(err.response);
                self.$bvToast.toast("Не удачный запрос. Попробуйте позже.", {
                    title: 'Ошибка',
                    autoHideDelay: 3000,
                    variant: 'error',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });
                this.message = "";
            });
        }
    },
    created(){
        let self = this;

        this.$axios({
            method: 'GET',
            url: settings.apiUrl + '/manufacture/'+ this.$route.params.presentation +'/order/',
        }).then(resp => {
            let result = resp.data.data;
            
            this.id = result.id;
            this.collectionName = result.collectionName;
            this.orderId = result.orderId;
            this.basket = result.basket;

        })
        .catch(err => {
            self.$bvToast.toast(err, {
                    title: 'Ошибка',
                    autoHideDelay: 3000,
                    variant: 'error',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });
        })
    },
    mounted(){
        // добалевление товара в корзину отстройки
        this.$on('setQuantity', function (responce) {
            this.quantity = responce;
        });
    }
}
</script>
<style lang="scss" scoped>
    .order-list{
        width: 100%;
    }
    .order-list > div{
        width: 100%;
    }
</style>