<template>
    <div class="order-item" :class="{showImg: showFullImg}">
        <div class="front">
            <div class="order-item__img-block" v-on:click="showFullImg = true">
                <img :src="item.picture" alt="">
            </div>
            <div class="order-item__discription-block">
                <p class="order-item__title">{{item.productName}}</p>
                <div class="order-options" v-for="(offer, index) in item.sku" :key="index">
                    <div class="order-options__item" v-if="isSize">
                        <p class="order-options__title">Размер:</p>
                        <p class="order-options__name">{{offer.prop.size.title}}</p>
                    </div>
                    <div class="order-options__item" v-if="isColor">
                        <p class="order-options__title">Цвет:</p>
                        <p class="order-options__name">{{offer.prop.color.title}}</p>
                    </div>
                    <div class="order-options__item" v-if="isOrientation">
                        <p class="order-options__title">Ориентация: </p>
                        <p class="order-options__name">{{offer.prop.orientation.title}}</p>
                    </div>
                    <div class="order-options__item">
                        <p class="order-options__title">Количество:</p>
                        <p class="color-item__quantity">{{offer.quantity}}</p>
                    </div>
                    <div class="order-options__item">
                        <p class="order-options__title">Отстройка шт:</p>
                        <div class="input-block">
                            <span class="minus" @click="minus(offer.id)"></span>
                            <input 
                                type="number"  
                                min="0" 
                                @input="setQuantity($event.target.value, offer.id)" 
                                v-bind:placeholder="offer.quantity"  
                                v-bind:value="getQuantity(offer.id)">
                            <span class="plus" @click="plus(offer.id)"></span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div class="back" v-bind:style="{ backgroundImage: 'url('+ item.picture +')' }" v-on:click="showFullImg = false"></div>
    </div>
