</template>
<script>
export default {
    name: 'manufactureOrderBasketItem',
    props: [
        "item"
    ],
    data: function(){
        return {
            id: 0,
            productInfo: {},
            offerList: [],
            isSize: false,
            isColor: false,
            isOrientation: false,
            quantity: [],
            iteration: 0,
            showFullImg: false
        }
    },
    methods: {
        getQuantity(id){
            let i = 0;

            $.each(this.quantity, function (key, item) {
                if (item.basketItemId == id) {
                    i = item.value;
                }
            });
            
            return i
        },
        setQuantity(res, id){
            let set = false;

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].basketItemId == id) {
                        set = true;
                        this.quantity[i].value = parseInt(res | 0);
                        this.iteration++;
                    }
                }
            }
            
            if (!set) {
                this.quantity.push({
                    'basketItemId': id,
                    'value': parseInt(res)
                });
                this.iteration++;
            }
        },
        plus(id){
            let set = false;

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].basketItemId == id) {
                        set = true;
                        this.quantity[i].value++;
                        this.iteration++;
                    }
                }
            }

            if (!set) {
                this.quantity.push({
                    'basketItemId': id,
                    'value': 1
                });
                this.iteration++;
            }
        },
        minus(id){
            let set = false;

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].basketItemId == id) {
                        set = true;
                        if(parseInt(this.quantity[i].value) > 0){
                            this.quantity[i].value--;
                        }
                        else{
                            this.quantity[i].value = 0;
                        }
                        this.iteration++;
                    }
                }
            }

            if (!set) {
                this.quantity.push({
                    'basketItemId': id,
                    'value': 0
                });
                this.iteration++;
            }
        },
        stopEvent(e){
            e.stopPropagation();
        },
        setParams(){
            let self = this;
            if(typeof this.productInfo != "undefined"){
                    $.each(this.productInfo.sku, function(offerId, offer){
                        if(offer.prop.color.title){
                            self.isColor = true;
                        }
                        if(offer.prop.size.title){
                            self.isSize = true;
                        }
                        if(offer.prop.orientation.title){
                            self.isOrientation = true;
                        }
                    });
                    
                }
        }
    },
    computed: {
        countOffers(){
            return Object.keys(this.productInfo.sku).length;
        }
    },
    watch: {
        iteration: function(){
            this.$parent.$emit('setQuantityManufacture', {'items': this.quantity, 'productId':this.productInfo.id});
        }
    },
    created() {
        this.productInfo = this.$props.item;
        this.setParams();
    },
}
</script>
