        }
        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }

        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }

        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }
    }
    .order-item.showImg .front {transform: rotateY(180deg);}
    .order-item.showImg .back {transform: rotateY(360deg);}
</style>