<template>
    <div>
        <div class="preloader" v-if="!countItems"><b-spinner variant="primary" type="grow" label="Spinning"></b-spinner></div>
        <div class="order-items" v-if="countItems">
            <manufactureBasketItem 
            v-for="(element, index) in basket" 
            v-bind:key="index" 
            v-bind:item="element"></manufactureBasketItem>
        </div>
        <div class="order-items" v-if="!countItems">
            Загрузка...
        </div>
    </div>
</template>
<script>
import ManufactureBasketItem from "@/components/manufacture/basketItem";
export default {
    name: 'manufactureOrderList',
    components: {
        ManufactureBasketItem
    },
    props: [
        "basket"
    ],
    data: function(){
        return {
            quantity: []
        }
    },
    methods: {
        bindQuantityList(items){
            let oldItems = this.quantity;
            
            let newItems = oldItems.concat(items);
            
            // делаем проход по новому и собираем повторяющиеся позиции
            if(newItems.length > 0){
                let result = [];
                let tmp = [];

                for(let i = 0; i < newItems.length; i++){
                    let itemOrigin = newItems[i];

                    // проверяем актуальность, чтобы избежать дублей
                    let isActial = true;
                    for(let k = 0; k < tmp.length; k++){
                        if(parseInt(tmp[k]) === parseInt(itemOrigin.basketItemId)){
                            isActial = false;
                        }
                    }

                    if(isActial){
                        let sum = parseInt(itemOrigin.value);
                        for(let j = 0; j < newItems.length; j++){
                            let itemDuplicate = newItems[j];
                            if(j != i){
                                // собрать суммарное кол-во
                                if(parseInt(itemDuplicate.basketItemId) === parseInt(itemOrigin.basketItemId)){
                                    sum = parseInt(itemDuplicate.value);
                                }
                            }
                        }

                        result.push({
                            'basketItemId': itemOrigin.basketItemId,
                            'value': parseInt(sum)
                        });

                        tmp.push(itemOrigin.basketItemId);
                        
                    }
                }

                this.quantity = result;
            }
            else{
                this.quantity = items;
            }
        }
    },
    watch: {
        quantity: function(){
            this.$parent.$emit('setQuantity', this.quantity);
        }
    },
    computed: {
        countItems: function () {
            return Object.keys(this.$props.basket).length;
		},
    },
    mounted(){
        let self = this;
        // добалевление товара в корзину отстройки
        this.$on('setQuantityManufacture', function (responce) {
            self.bindQuantityList(responce.items);
        });
        
    }
}
</script>